          }
        ]
      }
    ],
    "SessionEnd": [
      {
        "matcher": "",
        "hooks": [
          {
            "type": "command",
            "command": "entire hooks claude-code session-end"
          }
        ]
      },
      {
        "hooks": [
          {
            "type": "command",
            "command": "brain system end-session"
          }
        ]
      }
    ],
    "SessionStart": [
      {
        "matcher": "",
        "hooks": [
          {
            "type": "command",
            "command": "entire hooks claude-code session-start"
          }
        ]
      },
      {
        "hooks": [
          {
            "type": "command",
            "command": "brain system load-context"
          }
        ]
      }
    ],
    "Stop": [
      {
        "matcher": "",
        "hooks": [
          {
            "type": "command",
            "command": "entire hooks claude-code stop"
          }
        ]
      },
      {
        "hooks": [
          {
            "type": "prompt",
            "prompt": "Review this conversation for items that were discussed but NOT logged via the Brain MCP tools. Check each category:\n\n1. **Decisions**: Implementation choices made but not logged. Call create_provisional_decision for each.\n2. **Questions**: Unresolved questions raised but not logged. Call ask_question for each.\n3. **Observations**: Contradictions, duplication, missing items, deprecated patterns, or anomalies noticed. Call log_observation for each.\n4. **Task progress**: Tasks worked on whose status wasn't updated. Call update_task_status for each.\n5. **Subtasks identified**: Work items or follow-up tasks discussed but not created. Call create_subtask for each (requires a parent task).\n6. **Suggestions**: Optimizations, risks, opportunities, missing elements, or potential pivots noticed during work. Call create_suggestion for each with category (optimization|risk|opportunity|conflict|missing|pivot), rationale, and confidence (0-1).\n\nAfter logging everything, respond with valid JSON in this exact shape:\n{\"decision\":\"approve\",\"summary\":\"<one-line session summary>\",\"decisions_made\":[\"<decision-id>\"],\"questions_asked\":[\"<question-id>\"],\"tasks_progressed\":[{\"task_id\":\"<task-id>\",\"from_status\":\"<from>\",\"to_status\":\"<to>\"}],\"files_changed\":[{\"path\":\"<path>\",\"change_type\":\"created|modified|deleted\"}],\"observations_logged\":[\"<observation-id>\"],\"subtasks_created\":[\"<subtask-id>\"],\"suggestions_created\":[\"<suggestion-id>\"]}\n\nIf you cannot log required items (for example MCP unavailable), respond with:\n{\"decision\":\"block\",\"reason\":\"Log these items first: ...\"}"
          }
        ]
      }
    ],
    "UserPromptSubmit": [
      {
        "matcher": "",
        "hooks": [
          {
            "type": "command",
            "command": "entire hooks claude-code user-prompt-submit"
          }
        ]
      },
      {
        "hooks": [
          {
            "type": "command",
            "command": "brain system check-updates"
          }
        ]
      }
    ]
  },
  "permissions": {
    "deny": [
      "Read(./.entire/metadata/**)"
    ]
  }
}

